class Solution {
public:
    vector<string> getLetterCombinations(string inputDigits) {
        if (inputDigits.empty()) return {};

        vector<string> keypad = {
            "", "", "abc", "def", "ghi", "jkl",
            "mno", "pqrs", "tuv", "wxyz"
        };

        vector<string> result;
        string current;

        function<void(int)> backtrack = [&](int index) {
            if (index == inputDigits.size()) {
                result.push_back(current);
                return;
            }

            int digit = inputDigits[index] - '0';
            for (char c : keypad[digit]) {
                current.push_back(c);
                backtrack(index + 1);
                current.pop_back();
            }
        };

        backtrack(0);
        return result;
    }
};

