void getLetterCombinations(char digits[], char result[][10], int *resIndex) {
    int n = strlen(digits);
    *resIndex = 0;

    if (n == 0) return;

    // Nested recursive function
    void backtrack(int index) {
        if (index == n) {
            strcpy(result[(*resIndex)++], current);
            return;
        }

        char *letters = keypad[digits[index] - '0'];
        for (int i = 0; letters[i] != '\0'; i++) {
            current[index] = letters[i];
            backtrack(index + 1);
        }
    }

    backtrack(0);
}

