class Solution {
    constructor() {
        this.keypad = [
            "", "", "abc", "def", "ghi", "jkl",
            "mno", "pqrs", "tuv", "wxyz"
        ];
    }

    getLetterCombinations(inputDigits) {
        if (inputDigits.length === 0) return [];

        const result = [];
        let current = [];

        const backtrack = (index) => {
            if (index === inputDigits.length) {
                result.push(current.join(''));
                return;
            }

            const letters = this.keypad[inputDigits[index] - '0'];
            for (let ch of letters) {
                current.push(ch);
                backtrack(index + 1);
                current.pop();
            }
        };

        backtrack(0);
        return result;
    }
}
